scwin.f_ValidateAset = async function () {
  for (var i = 0; i < ds_master.getTotalRow(); i++) {
    if (ds_master.getCellData(i, "procYn") == 1 || ds_master.getRowStatus(i) == "U") {
      // if(ds_master.getCellData(i, "numCheck") != "1"){
      if (ds_master.getCellData(i, "procQty") <= 0) {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_003, ["폐기수량"]);
        // gr_master.SetColumn("procQty");
        return false;
      }
      // }

      if (ds_master.getCellData(i, "procQty") > ds_master.getCellData(i, "qty")) {
        await $c.gus.cfAlertMsg($p, "폐기수량이 수량을 초과하였습니다.");
        // gr_master.SetColumn("procQty");
        return false;
      }

      /*if (ds_master.NameValue(i,"acqDt") > ed_procDt.text) {
          cfAlertMsg("자산번호 " + ds_master.NameString(i,"fixedAsetNo") + " 의 폐기일자가 취득일자 이전입니다.");
          gr_master.SetColumn("fixedAsetNo");
          return false;
      }*/
      if (ds_master.getCellData(i, "procRate") == "100") {
        if (ds_master.getCellData(i, "procQty") != ds_master.getCellData(i, "qty")) {
          await $c.gus.cfAlertMsg($p, "비율이 100(%)인경우 수량과 폐기수량은 일치해야합니다.");
          // gr_master.SetColumn("procQty");
          return false;
        }
      }
    }
  }
  return true;
};

