scwin.ds_master_onrowpositionchange = function (info) {
  var row = info.rowIndex;
  if (ds_master.getCellData(row, "procYn") == 1) {
    if (ds_master.getCellData(row, "qty") == 1) {
      gr_master.setReadOnly("cell", row, "procQty", false);
      gr_master.setReadOnly("cell", row, "procRate", false);
    } else {
      gr_master.setReadOnly("cell", row, "procQty", false);
      gr_master.setReadOnly("cell", row, "procRate", false);
    }
    gr_master.setReadOnly("cell", row, "procAmt", false);
    gr_master.setReadOnly("cell", row, "reappraiseAmt", false);
    gr_master.setReadOnly("cell", row, "procArea", false);
  } else {
    gr_master.setReadOnly("cell", row, "procQty", true);
    gr_master.setReadOnly("cell", row, "procAmt", true);
    gr_master.setReadOnly("cell", row, "procRate", true);
    gr_master.setReadOnly("cell", row, "reappraiseAmt", true);
    gr_master.setReadOnly("cell", row, "procArea", true);
  }
};
scwin.ds_master_oncelldatachange = async function (info) {
  var colid = info.colID;
  var row = info.rowIndex;
  if (colid == "procYn" && ds_master.getCellData(row, "procYn") == 0) {
    ds_master.setCellData(row, "procQty", 0);
    ds_master.setCellData(row, "procAmt", 0);
    ds_master.setCellData(row, "procAcqAmt", 0);
    ds_master.setCellData(row, "procRate", 0);
    ds_master.setCellData(row, "procBefYyProvAmt", 0);
    ds_master.setCellData(row, "procThisYyProvAmt", 0);
    ds_master.setCellData(row, "procBookAmt", 0);
    ds_master.setCellData(row, "procDifferAmt", 0);
    return;
  }
  if (colid == "procYn" && ds_master.getCellData(row, "procYn") == "1" && ds_master.getCellData(row, "lentYn") == "1") {
    ds_master.setCellData(row, "procYn", 0);
    await $c.gus.cfAlertMsg($p, "임대중인  자산은 처리할 수 없습니다.");
    return;
  }
  if (ds_master.getCellData(row, "asetPatternNm") == "토지" || ds_master.getCellData(row, "asetPatternNm") == "건물") {
    if (colid == "procArea") {
      // asis에서는 수정시 procQty에 0이 아닌값 세팅함. validationCheck위해 처리  
      // var chechNum = Math.floor(Number(ds_master.getCellData(row, "procArea")) / Number(ds_master.getCellData(row, "area")) * 10000)/100; 
      // if(chechNum == 0){
      //     ds_master.setCellData(row, "numCheck", 1);
      // }
      // ds_master.setCellData(row, "procRate", Math.floor(Number(ds_master.getCellData(row, "procArea")) / Number(ds_master.getCellData(row, "area")) * 10000)/100);

      ds_master.setCellData(row, "procRate", ds_master.getCellData(row, "procArea") / ds_master.getCellData(row, "area") * 100);
      // ds_master.setCellData(row, "procRate", 0.001520843155445379);
      var procRate = Number(ds_master.getCellData(row, "procRate")) / 100;
      ds_master.setCellData(row, "procQty", Number(ds_master.getCellData(row, "qty")) * procRate);
    }
  } else {
    if (colid == "procQty") {
      ds_master.setCellData(row, "procRate", Math.floor(Number(ds_master.getCellData(row, "procQty")) / Number(ds_master.getCellData(row, "qty")) * 10000) / 100);
      var procRate = Number(ds_master.getCellData(row, "procRate")) / 100;
    }
  }

  //수량이 1개인 자산을 부분처리할경우 비율 입력시 수량 소숫점 자동 계산 (부분처리를 위함)
  if (colid == "procRate" && ds_master.getCellData(row, "qty") == 1) {
    const factor = Math.pow(10, 3);
    var num = Number(ds_master.getCellData(row, "procRate")) * Number(ds_master.getCellData(row, "qty")) / 100;
    var formatNum = Math.floor(num * factor) / factor;
    ds_master.setCellData(row, "procQty", formatNum);

    // ds_master.setCellData(row, "procQty", (Number(ds_master.getCellData(row, "procRate")) * Number(ds_master.getCellData(row, "qty"))) / 100);
    // var procQty = ds_master.getCellData(row, "procQty");
  }
  if (colid == "procRate") {
    var procRate = Number(ds_master.getCellData(row, "procRate") / 100);

    //ds_master.NameValue(row,"procRate") =  (ds_master.NameValue(row, "procQty") / ds_master.NameValue(row, "qty") )   * 100 ;

    ds_master.setCellData(row, "procAcqAmt", Math.round(Number(ds_master.getCellData(row, "acqAmt")) * procRate));
    ds_master.setCellData(row, "procBefYyProvAmt", Math.round(Number(ds_master.getCellData(row, "befYyProvAmt")) * procRate));
    ds_master.setCellData(row, "procThisYyProvAmt", Math.round(Number(ds_master.getCellData(row, "thisYyProvAmt")) * procRate));
    ds_master.setCellData(row, "procBookAmt", Number(ds_master.getCellData(row, "procAcqAmt")) - (Number(ds_master.getCellData(row, "procBefYyProvAmt")) + Number(ds_master.getCellData(row, "procThisYyProvAmt"))));
    ds_master.setCellData(row, "procDifferAmt", ds_master.getCellData(row, "procBookAmt"));
  }
};
